import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,e as d}from"./app-be253e4c.js";const o={},c=d('<h1 id="工厂方法模式" tabindex="-1"><a class="header-anchor" href="#工厂方法模式" aria-hidden="true">#</a> 工厂方法模式</h1><p>工厂方法模式<code>Factory Method Pattern</code>又称为工厂模式，也叫虚拟构造器<code>Virtual Constructor</code> 模式或者多态工厂<code>Polymorphic Factory</code> 模式，它属于类创建型模式，在工厂方法模式中，工厂父类负责定义创建产品对象的公共接口，而工厂子类则负责生成具体的产品对象，这样做的目的是将产品类的实例化操作延迟到工厂子类中完成，即通过工厂子类来确定究竟应该实例化哪一个具体产品类。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>简单工厂模式有一个问题，类的创建依赖工厂类，也就是说如果想要拓展程序，必须对工厂类进行修改，而工厂方法模式就是将具体的创建过程交给专门的工厂子类去完成，即将产品类的实例化操作延迟到工厂子类中完成，由此可以不必再去修改工厂类，而只需要定义实现工厂的子类即可。</p><h3 id="模式分析" tabindex="-1"><a class="header-anchor" href="#模式分析" aria-hidden="true">#</a> 模式分析</h3><p>工厂方法模式是简单工厂模式的进一步抽象和推广。由于使用了面向对象的多态性，工厂方法模式保持了简单工厂模式的优点，而且克服了它的缺点。在工厂方法模式中，核心的工厂类不再负责所有产品的创建，而是将具体创建工作交给子类去做。这个核心类仅仅负责给出具体工厂必须实现的接口，而不负责哪一个产品类被实例化这种细节，这使得工厂方法模式可以允许系统在不修改工厂角色的情况下引进新产品。</p><h3 id="模式结构" tabindex="-1"><a class="header-anchor" href="#模式结构" aria-hidden="true">#</a> 模式结构</h3><ul><li><code>Product</code>：抽象产品。</li><li><code>ConcreteProduct</code>：具体产品。</li><li><code>Factory</code>：抽象工厂。</li><li><code>ConcreteFactory</code>：具体工厂。</li></ul><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>在工厂方法模式中，工厂方法用来创建客户所需要的产品，同时还向客户隐藏了哪种具体产品类将被实例化这一细节，用户只需要关心所需产品对应的工厂，无须关心创建细节，甚至无须知道具体产品类的类名。</li><li>基于工厂角色和产品角色的多态性设计是工厂方法模式的关键。它能够使工厂可以自主确定创建何种产品对象，而如何创建这个对象的细节则完全封装在具体工厂内部。工厂方法模式之所以又被称为多态工厂模式，是因为所有的具体工厂类都具有同一抽象父类。</li><li></li></ul><p>使用工厂方法模式的另一个优点是在系统中加入新产品时，无须修改抽象工厂和抽象产品提供的接口，无须修改客户端，也无须修改其他的具体工厂和具体产品，而只要添加一个具体工厂和具体产品就可以了。这样，系统的可扩展性也就变得非常好，完全符合“开闭原则”。</p><h3 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点" aria-hidden="true">#</a> 缺点</h3><ul><li>在添加新产品时，需要编写新的具体产品类，而且还要提供与之对应的具体工厂类，系统中类的个数将成对增加，在一定程度上增加了系统的复杂度，有更多的类需要编译和运行，会给系统带来一些额外的开销。</li><li>由于考虑到系统的可扩展性，需要引入抽象层，在客户端代码中均使用抽象层进行定义，增加了系统的抽象性和理解难度，且在实现时可能需要用到反射等技术，增加了系统的实现难度。</li></ul><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',14),i=[c];function t(h,l){return a(),r("div",null,i)}const u=e(o,[["render",t],["__file","factory-method-mode.html.vue"]]);export{u as default};
